module decoder_3to8(A,EN,Y);
input [2:0] A;
input EN;
output reg [7:0] Y;

always @(*) begin
	if (!EN)
		Y = 8'b00000000;
	else
		Y = 8'b00000001 << A;
end

  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~EN & A[0];
      Y[1] <= ~EN & A[1];
      Y[2] <= ~EN & A[2];
      Y[3] <= ~EN & A[3];
      Y[4] <= ~EN & A[4];
      Y[5] <= ~EN & A[5];
      Y[6] <= ~EN & A[6];
      Y[7] <= ~EN & A[7];
    end
  end

endmodule
